import{_ as t,o as r,c as n,a4 as o}from"./chunks/framework.CgwWDRUJ.js";const m=JSON.parse('{"title":"4. Glossary","description":"","frontmatter":{},"headers":[],"relativePath":"rad/glossary.md","filePath":"rad/glossary.md"}'),a={name:"rad/glossary.md"};function s(i,e,g,p,l,c){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="_4-glossary" tabindex="-1">4. Glossary <a class="header-anchor" href="#_4-glossary" aria-label="Permalink to “4. Glossary”">​</a></h1><p>Definitions of technical and domain-specific terms used in this document.</p><h2 id="general-terms" tabindex="-1">General Terms <a class="header-anchor" href="#general-terms" aria-label="Permalink to “General Terms”">​</a></h2><p><strong>Avatar</strong>: A user-selected image that represents their profile visually across the platform.</p><p><strong>Compatibility Score</strong>: A numerical percentage (0-100%) indicating how well two travelers match based on interests, travel style, and preferences.</p><p><strong>Community Guidelines</strong>: Rules and policies that users must follow to maintain a safe, respectful platform.</p><p><strong>Destination</strong>: A geographic location (city, region, country) that users can visit and select as favorites.</p><p><strong>Discovery/Feed</strong>: A personalized list of recommended travelers or trips based on user preferences and matching algorithms.</p><p><strong>GDPR (General Data Protection Regulation)</strong>: European privacy regulation ensuring user data protection rights.</p><p><strong>Itinerary</strong>: A detailed plan of activities and schedule for a trip, including dates, times, and locations.</p><p><strong>Match</strong>: A potential travel companion identified by the system as compatible based on criteria.</p><p><strong>Onboarding</strong>: The process new users go through to set up their account and complete their profile.</p><p><strong>Privacy Settings</strong>: User-controlled options to determine visibility and information sharing on the platform.</p><p><strong>Profile</strong>: A user&#39;s account information including personal details, interests, and preferences.</p><p><strong>Saved Items</strong>: Profiles or trips users have bookmarked for later reference.</p><p><strong>Trip</strong>: A planned travel event created by a user, with specific destination, dates, and details.</p><p><strong>User</strong>: Any person registered on the TravelMate platform.</p><p><strong>Verification</strong>: Confirmation of user identity through email validation and profile checks.</p><h2 id="user-roles" tabindex="-1">User Roles <a class="header-anchor" href="#user-roles" aria-label="Permalink to “User Roles”">​</a></h2><p><strong>Unauthenticated User/Guest</strong>: A person who can view public content but hasn&#39;t registered or logged in.</p><p><strong>Administrator</strong>: A staff member with elevated permissions to moderate content, handle reports, and manage platform operations.</p><p><strong>Traveler User</strong>: Authenticated users who can search for companions, create trips, and interact with other travelers.</p><p><strong>Trip Creator</strong>: A traveler who initiates and organizes a specific trip.</p><p><strong>Trip Participant</strong>: A traveler who has joined an existing trip created by another user.</p><h2 id="technical-terms" tabindex="-1">Technical Terms <a class="header-anchor" href="#technical-terms" aria-label="Permalink to “Technical Terms”">​</a></h2><p><strong>API (Application Programming Interface)</strong>: Set of protocols allowing communication between frontend and backend systems.</p><p><strong>Authentication</strong>: Process of verifying a user&#39;s identity, typically through login credentials.</p><p><strong>Authorization</strong>: Process of determining what authenticated users are allowed to do.</p><p><strong>Bcrypt</strong>: A password hashing algorithm used to securely store passwords.</p><p><strong>Backend</strong>: Server-side infrastructure handling business logic and data management.</p><p><strong>Cache/Caching</strong>: Temporary storage of frequently accessed data for faster retrieval.</p><p><strong>Database</strong>: Organized collection of data stored persistently, using PostgreSQL in this project.</p><p><strong>Django</strong>: Python web framework used for building the backend API.</p><p><strong>Django REST Framework</strong>: Extension for Django enabling RESTful API development.</p><p><strong>Encryption</strong>: Conversion of data into coded form to prevent unauthorized access.</p><p><strong>Endpoint</strong>: Specific URL path in an API that clients can request.</p><p><strong>Flutter</strong>: Google&#39;s mobile app development framework used for iOS and Android apps.</p><p><strong>Frontend</strong>: Client-side user interface and application logic.</p><p><strong>JSON (JavaScript Object Notation)</strong>: Lightweight data format used for API responses.</p><p><strong>JWT (JSON Web Token)</strong>: Token-based authentication method for APIs.</p><p><strong>Load Balancing</strong>: Distribution of traffic across multiple servers for scalability.</p><p><strong>Middleware</strong>: Software layer handling cross-cutting concerns (logging, auth, etc.).</p><p><strong>MVC/MVVM</strong>: Architectural patterns separating concerns (Model, View, Controller/ViewModel).</p><p><strong>ORM (Object-Relational Mapping)</strong>: Technology mapping database records to application objects.</p><p><strong>PostgreSQL</strong>: Open-source relational database management system.</p><p><strong>Python</strong>: Programming language used for backend development.</p><p><strong>Rate Limiting</strong>: Restricting number of requests a user can make in a time period.</p><p><strong>Redis</strong>: In-memory data store used for caching and session management.</p><p><strong>REST (Representational State Transfer)</strong>: Architectural style for API design using HTTP methods.</p><p><strong>Scalability</strong>: System&#39;s ability to handle increasing load and users.</p><p><strong>Schema</strong>: Definition of database structure including tables and relationships.</p><p><strong>SSL/TLS</strong>: Security protocols for encrypted communication over networks.</p><p><strong>Token</strong>: Authentication credential issued after successful login, used to access APIs.</p><p><strong>Validation</strong>: Process of checking user input for correctness and safety.</p><p><strong>Webhook</strong>: Automatic callback mechanism triggering external systems on events.</p><h2 id="business-terms" tabindex="-1">Business Terms <a class="header-anchor" href="#business-terms" aria-label="Permalink to “Business Terms”">​</a></h2><p><strong>Budget Range</strong>: The estimated cost per person for a trip (Budget/Mid-range/Luxury).</p><p><strong>Companion Search</strong>: Process of finding compatible travel partners through the platform.</p><p><strong>Flexibility Level</strong>: How willing a traveler is to adapt plans (Very Flexible/Moderately Flexible/Set Plans).</p><p><strong>Interest Category</strong>: Classification of hobbies and preferences (e.g., Adventure, Culture, Food).</p><p><strong>Language Preference</strong>: Languages a user speaks and prefers for communication.</p><p><strong>Matching Algorithm</strong>: System logic determining compatibility between travelers.</p><p><strong>Moderation</strong>: Process of reviewing and managing user-generated content for compliance.</p><p><strong>Notification</strong>: Automatic message alerting users to important events or messages.</p><p><strong>Report</strong>: User submission flagging inappropriate content or behavior.</p><p><strong>Review/Rating</strong>: User feedback about another traveler&#39;s compatibility and experience.</p><p><strong>Saved Profile</strong>: A traveler has bookmarked another user&#39;s profile for later reference.</p><p><strong>Search Filter</strong>: Criteria used to narrow down available options (age, interests, location, etc.).</p><p><strong>Travel Companion</strong>: A fellow traveler selected or matched for a journey.</p><p><strong>Travel Style</strong>: The approach to travel reflecting preferences and values (adventurous, relaxed, cultural, etc.).</p><h2 id="functional-area-terms" tabindex="-1">Functional Area Terms <a class="header-anchor" href="#functional-area-terms" aria-label="Permalink to “Functional Area Terms”">​</a></h2><h3 id="user-management" tabindex="-1">User Management <a class="header-anchor" href="#user-management" aria-label="Permalink to “User Management”">​</a></h3><p><strong>Account</strong>: User&#39;s registered identity in the system. <strong>Profile Completion</strong>: Percentage of profile information filled out. <strong>Session</strong>: Active login period for a user. <strong>Two-Factor Authentication (2FA)</strong>: Enhanced security requiring secondary verification method.</p><h3 id="communication" tabindex="-1">Communication <a class="header-anchor" href="#communication" aria-label="Permalink to “Communication”">​</a></h3><p><strong>Group Chat</strong>: Conversation involving trip participants or multiple users. <strong>Direct Message (DM)</strong>: Private 1-on-1 conversation between two users. <strong>Message Status</strong>: Indicator showing if message is sent, delivered, or read. <strong>Online Status</strong>: Real-time indicator showing if user is currently using the app.</p><h3 id="trip-management" tabindex="-1">Trip Management <a class="header-anchor" href="#trip-management" aria-label="Permalink to “Trip Management”">​</a></h3><p><strong>Access Code</strong>: Unique identifier to join a private trip. <strong>Itinerary Item</strong>: Individual activity/event in a trip schedule. <strong>Max Participants</strong>: Maximum number of people allowed to join a trip. <strong>Trip Status</strong>: Current state of a trip (Draft, Published, Ongoing, Completed, Cancelled).</p><h3 id="safety-moderation" tabindex="-1">Safety &amp; Moderation <a class="header-anchor" href="#safety-moderation" aria-label="Permalink to “Safety &amp; Moderation”">​</a></h3><p><strong>Block</strong>: Action preventing another user from contacting or viewing profile. <strong>Inappropriate Content</strong>: Material violating community guidelines. <strong>Moderation Queue</strong>: Administrative system for reviewing flagged content. <strong>Suspension</strong>: Temporary restriction of account access. <strong>Warning</strong>: First-step notice to user about guideline violation.</p>',79)])])}const u=t(a,[["render",s]]);export{m as __pageData,u as default};
